  "1025": {
    name: {
      en: "Donator Status Ticket - 7 DAYS",
      cn: "\u6350\u8D60\u8005\u72B6\u6001\u52B5(Donator Status Ticket) - 7\u5929",
      de: "Spenderstatus-Ticket - 7 Tage",
      fr: "Ticket Statut Donateur - 7 Jours",
      it: "Biglietto Stato Donatore - 7 Giorni",
      es: "Ticket de Estado Donador - 7 D\xCDAS",
      ja: "Donator Status Ticket - 7 DAYS",
      tw: "\u6350\u8D08\u8005\u72C0\u614B\u52B5(Donator Status Ticket) - 7\u5929"
    },
    description: {
      en: "An item which can be used to promote\nyour account to Donator Status.\n\nDonator Status benefits include:\n+25% EXP in battles.\n+10% chance of encountering shinies.\n+10% faster egg hatching.\n+5% money gain from trainers.",
      cn: "\u53EF\u7528\u4E8E\u63D0\u5347\u8D26\u6237\u4E3A\u6350\u8D60\u8005\u72B6\u6001.\n\n\u6350\u8D60\u8005\u72B6\u6001\u76CA\u5904\u5305\u62EC:\n\u6218\u6597\u4E2D+25%\u7ECF\u9A8C.\n\u9047\u95EA\u51E0\u7387+10%.\n\u5B75\u86CB\u901F\u5EA6+10%.\n\u8BAD\u7EC3\u5BB6\u8D62\u94B1+5%.",
      de: "Ein Gegenstand, der benutzt werden\nkann,\num deinem Konto, Spenderstatus zu\nverleihen.\n\nVorteile des Spenderstatus\nbeinhalten:\n+25% EP in K\xE4mpfen.\n+10% Chance Shinies zu begegnen.\n+10% k\xFCrzere Schl\xFCpfzeit f\xFCr Eier.\n5% mehr Geld aus Trainerk\xE4mpfen.",
      fr: "Un objet qui peut \xEAtre utilis\xE9 pour\npromouvoir votre compte en Statut\nDonateur.\n\nLes avantages incluent:\n+25% XP en combat.\n+10% de chances de rencontrer un\nchromatique.\n+10% de vitesse d'\xE9closion d'\u0153ufs.\n+5% d'argent gagn\xE9 gr\xE2ce aux\ndresseurs.",
      it: "Un oggetto che pu\xF2 essere utilizzato\nper\npromuovere il tuo account allo Stato\ndi Donatore.\n\nI vantaggi per lo Stato di Donatore\nincludono:\n+25% di esperienza in battaglia.\n+10% di possibilit\xE0 di incontrare\ncromatici.\n+10% di velocit\xE0 nella schiusura delle\nuova.\n+5% di guadagno in denaro dagli\nallenatori.",
      es: "Objeto que puede utilizarse para\nascender\ntu cuenta a Estado Donador.\n\nLos beneficios del Estado Donador\nincluyen:\n+25% de EXP en combates.\n+10% de probabilidad de\nencontrar variocolores.\n+10% eclosi\xF3n de huevos m\xE1s r\xE1pida.\n+5% dinero obtenido de entrenadores.",
      ja: "An item which can be used to promote\nyour account to Donator Status.\n\nDonator Status benefits include:\n+25% EXP in battles.\n+10% chance of encountering shinies.\n+10% faster egg hatching.\n+5% money gain from trainers.",
      tw: "\u53EF\u7528\u65BC\u63D0\u5347\u8CEC\u6236\u70BA\u6350\u8D08\u8005\u72C0\u614B.\n\n\u6350\u8D08\u8005\u72C0\u614B\u76CA\u8655\u5305\u62EC:\n\u6230\u9B25\u4E2D+25%\u7D93\u9A57.\n\u9047\u9583\u6A5F\u7387+10%.\n\u5B75\u86CB\u901F\u5EA6+10%.\n\u8A13\u7DF4\u5BB6\u8D0F\u9322+5%."
    }
  },
