  "1180": {
    name: {
      en: "Cut Ocarina",
      cn: "Cut\u9676\u7B1B",
      de: "Zerschneider-Ocarina",
      fr: "Ocarina Coupe",
      it: "Ocarina Taglio",
      es: "Ocarina de Corte",
      ja: "\u3044\u3042\u3044\u304E\u308A Ocarina",
      tw: "Cut\u9676\u7B1B"
    },
    description: {
      en: "Summons a Pok\xE9mon which will use Cut\noutside of a battle.\n\nCannot be used in certain instances.\n\nRequires a certain badge in each\nregion to use.",
      cn: "\u53EC\u5524\u4E00\u53EA\u80FD\u5728\u6218\u6597\u5916\u4F7F\u7528Cut\u7684Pok\xE9mon.\n\n\u4E00\u4E9B\u526F\u672C\u4E2D\u4E0D\u80FD\u4F7F\u7528.\n\n\u5728\u6BCF\u4E2A\u5730\u533A\u90FD\u9700\u8981\u83B7\u5F97\u76F8\u5E94\u5FBD\u7AE0\u624D\u80FD\u4F7F\u7528.",
      de: "Beschw\xF6rt ein Pok\xE9mon, das au\xDFerhalb\neines Kampfes Zerschneider einsetzt.\n\nKann in bestimmten Situationen nicht\neingesetzt werden.\n\nErfordert einen bestimmten Orden in\njeder Region.",
      fr: "Invoque un Pok\xE9mon qui utilise Coupe\nhors d'un combat.\n\nNe peut pas \xEAtre utilis\xE9 dans certains\nendroits.\n\nN\xE9cessite un certain badge dans chaque\nr\xE9gion pour \xEAtre utilis\xE9.",
      it: "Evoca un Pok\xE9mon che user\xE0 Taglio\nfuori dalla lotta.\n\nNon pu\xF2 essere usata in certe\ncircostanze.\n\nRichiede la specifica medaglia della\nregione per l'utilizzo.",
      es: "Invoca a un Pok\xE9mon que usar\xE1 Corte\nfuera de combate.\n\nNo puede ser utilizada en ciertas\nocasiones.\n\nRequiere una medalla espec\xEDfica en\ncada regi\xF3n.",
      ja: "Summons a \u30DD\u30B1\u30E2\u30F3 which will use\n\u3044\u3042\u3044\u304E\u308A outside of a battle.\n\nCannot be used in certain instances.\n\nRequires a certain badge in each\nregion to use.",
      tw: "\u53EC\u559A\u4E00\u96BB\u80FD\u5728\u6230\u9B25\u5916\u4F7F\u7528Cut\u7684Pok\xE9mon.\n\n\u4E00\u4E9B\u526F\u672C\u4E2D\u4E0D\u80FD\u4F7F\u7528.\n\n\u5728\u6BCF\u500B\u5730\u5340\u90FD\u9700\u8981\u7372\u5F97\u76F8\u61C9\u5FBD\u7AE0\u624D\u80FD\u4F7F\u7528."
    }
  },
