  "1225": {
    name: {
      en: "Red Envelope (2019)",
      cn: "\u7EA2\u5305 - 2019(Red Envelope)",
      de: "Roter Umschlag (2019)",
      fr: "Enveloppe Rouge (2019)",
      it: "Busta Rossa (2019)",
      es: "Sobre rojo (2019)",
      ja: "Red Envelope (2019)",
      tw: "\u7D05\u5305 - 2019(Red Envelope)"
    },
    description: {
      en: "A red envelope which contains an\nunknown reward.\n\nMay contain exclusive items for Lunar\nNew Year 2019.\nUse to open.",
      cn: "\u88C5\u7740\u795E\u79D8\u5956\u52B1\u7684\u7EA2\u5305.\n\u53EF\u80FD\u5185\u542B2019\u6625\u8282\u7684\u72EC\u5BB6\u7269\u54C1.\n\n\u4F7F\u7528\u540E\u6253\u5F00.",
      de: "Ein roter Umschlag, der eine\nunbekannte Belohnung enth\xE4lt.\n\nEr kann exklusive Gegenst\xE4nde f\xFCr das\nMondneujahr 2019 enthalten.\nZum \xD6ffnen verwenden.",
      fr: "Une enveloppe rouge contenant une\nr\xE9compense inconnue.\n\nPeut contenir un objet exclusif du\nNouvel An Lunaire 2019.\nUtilisez pour ouvrir.",
      it: "Una busta rossa che contiene una\nricompensa sconosciuta.\n\nPotrebbe contenere oggetti esclusivi\ndel Nuovo Anno Lunare 2019.\nUsa per aprirla.",
      es: "Un sobre rojo que contiene una\nrecompensa misteriosa.\n\nPuede contener objetos exclusivos del\nA\xF1o Nuevo Lunar 2019.\nUsa para abrir.",
      ja: "A red envelope which contains an\nunknown reward.\n\nMay contain exclusive items for Lunar\nNew Year 2019.\nUse to open.",
      tw: "\u88DD\u8457\u795E\u7955\u734E\u52F5\u7684\u7D05\u5305.\n\u53EF\u80FD\u5167\u542B2019\u6625\u7BC0\u7684\u7368\u5BB6\u7269\u54C1.\n\n\u4F7F\u7528\u5F8C\u958B\u555F."
    }
  },
