  "1238": {
    name: {
      en: "Pumpkin Cookie",
      cn: "\u5357\u74DC\u738B\u997C\u5E72(Pumpkin Cookie)",
      de: "K\xFCrbis-Keks",
      fr: "Cookie Citrouille",
      it: "Biscotto Zucca",
      es: "Galleta Calabaza",
      ja: "Pumpkin Cookie",
      tw: "\u5357\u74DC\u738B\u9905\u4E7E(Pumpkin Cookie)"
    },
    description: {
      en: "A tasty cookie exclusive to\nHalloween.\nIt restores HP when eaten, but causes\na Sugar Rush in battle.\n\nWhen fighting Pumpking, eating the\ncookie will heal the allied field by\n33% of their maximum HP.",
      cn: "\u4E07\u5723\u8282\u7279\u6709\u7684\u7F8E\u5473\u997C\u5E72.\n\u4F7F\u7528\u540E\u80FD\u6062\u590DHP, \u4F46\u4F1A\u5728\u5BF9\u6218\u4E2D\u89E6\u53D1\u751C\u7CD6\u51B2\u523A\u6548\u679C.\n\n\u5BF9\u6218\u5357\u74DC\u738B\u7684\u65F6\u5019, \u5403\u4E0B\u6B64\u997C\u5E72\u5C06\u6062\u590D\u5DF1\u65B9\u961F\u4F0D\u5404\u81EA33%\u7684\u6700\u5927HP.",
      de: "Ein leckerer Keks, den es nur an\nHalloween gibt.\nEr stellt HP wieder her, wenn er\ngegessen wird, verursacht aber einen\nZuckerrausch im Kampf.\nWenn du gegen den K\xFCrbisk\xF6nig k\xE4mpfst,\nheilt der Verzehr dieses Kekses das\nverb\xFCndete Feld um 33% der maximalen\nKP.",
      fr: "Un d\xE9licieux cookie exclusif \xE0\nHalloween.\nIl restaure les HP quand il est mang\xE9,\nmais provoque un Sugar Rush en\ncombat.\n\nEn combat contre le Pumpking, manger\nce cookie soignera le terrain alli\xE9\nde 33% de ses PV maximum.",
      it: "Un biscotto esclusivo di Halloween.\nMangiarlo fa recuperare PS, ma causa\nun picco di zuccheri in battaglia.\n\nContro il Re Zucca, mangiare questo\nbiscotto curer\xE0 gli alleati in campo\ndel 33% dei propri PS massimi.",
      es: "Una galleta sabrosa exclusiva de\nHalloween.\nRecupera PS al consumirla, pero causa\nuna Subida de Az\xFAcar en batalla.\n\nAl luchar contra el Rey Calabaza,\ncomer la galleta recupera los PS del\ncampo aliado un tercio de sus PS\nm\xE1ximos.",
      ja: "A tasty cookie exclusive to\nHalloween.\nIt restores HP when eaten, but causes\na Sugar Rush in battle.\n\nWhen fighting Pumpking, eating the\ncookie will heal the allied field by\n33% of their maximum HP.",
      tw: "\u842C\u8056\u7BC0\u7279\u6709\u7684\u7F8E\u5473\u9905\u4E7E.\n\u4F7F\u7528\u5F8C\u80FD\u6062\u5FA9HP, \u4F46\u6703\u5728\u5C0D\u6230\u4E2D\u89F8\u767C\u751C\u7CD6\u885D\u523A\u6548\u679C.\n\n\u5C0D\u6230\u5357\u74DC\u738B\u7684\u6642\u5019, \u5403\u4E0B\u6B64\u9905\u4E7E\u5C07\u6062\u5FA9\u5DF1\u65B9\u968A\u4F0D\u5404\u81EA33%\u7684\u6700\u5927HP."
    }
  },
