  "1412": {
    name: {
      en: "Riches Charm (+75%)",
      cn: "\u91D1\u94B1\u62A4\u7B26(Riches Charm) (+75%)",
      de: "Amulett der Reichen (+75%)",
      fr: "Charme D'argent (+75%)",
      it: "Amuleto Ricchezza (+75%)",
      es: "Amuleto Riqueza (+75%)",
      ja: "Riches Charm (+75%)",
      tw: "\u91D1\u9322\u8B77\u7B26(Riches Charm) (+75%)"
    },
    description: {
      en: "A charm which increases the money\ngained in trainer battles.\n\nDoes not stack with other money\nbonuses.\nConsumed upon use.\nEffects last 1 hour.\nLink members receive a 10% bonus.",
      cn: "\u589E\u52A0\u8BAD\u7EC3\u5BB6\u5BF9\u6218\u4E2D\u6240\u83B7\u91D1\u94B1\u7684\u62A4\u7B26.\n\n\u4E0D\u4E0E\u5176\u4ED6\u91D1\u94B1\u52A0\u6210\u76F8\u53E0\u52A0.\n\u4E00\u6B21\u6027\u6D88\u8017\u54C1.\n\u6709\u6548\u671F1\u5C0F\u65F6.\n\u5C0F\u961F\u6210\u5458\u989D\u5916\u6536\u76CA10%.",
      de: "Ein Talisman, der das in Trainerk\xE4mpf\nen gewonnene Geld erh\xF6ht. Kann nicht\nmit anderen Geldboni kombiniert\nwerden.\nWird bei Verwendung verbraucht.\nDie Wirkung h\xE4lt 1 Stunde an.\nLink-Mitglieder erhalten einen Bonus\nvon 10 %.",
      fr: "Un charme qui augmente l'argent gagn\xE9\nlors de combats contre les\ndresseurs.\n\nNe se cumule pas avec les autres bonus\nd'argent.\nConsomm\xE9 lors de l'utilisation..\nDure une heure.\nLes membres du lien re\xE7oivent 10% de\nbonus.",
      it: "Un amuleto che incrementa il denaro\nguadagnato dalle lotte contro gli\nallenatori.\n\nNon si accumula con altri bonus in\ndenaro.\nConsumato dopo l'uso.\nL'effetto dura 1 ora.\nI membri Link ricevono un bonus del\n10%.",
      es: "Amuleto que aumenta el dinero recibido\nen combates contra entrenadores.\n\nNo se acumula con otros bonus de\ndinero.\nSe consume al usarlo.\nSu efecto dura 1 hora.\nLos miembros del link reciben un bonus\ndel 10%.",
      ja: "A charm which increases the money\ngained in trainer battles.\n\nDoes not stack with other money\nbonuses.\nConsumed upon use.\nEffects last 1 hour.\nLink members receive a 10% bonus.",
      tw: "\u589E\u52A0\u8A13\u7DF4\u5BB6\u5C0D\u6230\u4E2D\u6240\u7372\u91D1\u9322\u7684\u8B77\u7B26.\n\n\u4E0D\u8207\u5176\u4ED6\u91D1\u9322\u52A0\u6210\u76F8\u758A\u52A0.\n\u4E00\u6B21\u6027\u6D88\u8017\u54C1.\n\u6709\u6548\u671F1\u5C0F\u6642.\n\u5C0F\u968A\u6210\u54E1\u984D\u5916\u6536\u76CA10%."
    }
  },
