  "1484": {
    name: {
      en: "Mystic Mirror",
      cn: "\u9B54\u955C(Mystic Mirror)",
      de: "Mystischer Spiegel",
      fr: "Miroir Magik",
      it: "Specchio Mistico",
      es: "Espejo M\xEDstico",
      ja: "Mystic Mirror",
      tw: "\u9B54\u93E1(Mystic Mirror)"
    },
    description: {
      en: "A mysterious mirror.\n\nAllows you to change any aspect of\nyour base appearance, including\ngender and skin tone.\n\nCan only be used once.",
      cn: "\u795E\u79D8\u7684\u955C\u5B50.\n\n\u53EF\u4EE5\u6539\u53D8\u57FA\u672C\u5916\u8C8C\u7684\u4EFB\u610F\u65B9\u9762, \u5305\u62EC\u6027\u522B\u548C\u80A4\u8272.\n\n\u53EA\u80FD\u7528\u4E00\u6B21.",
      de: "Ein geheimnisvoller Spiegel.\n\nErm\xF6glicht es dir, jeden Aspekt deines\nAussehens zu ver\xE4ndern, einschlie\xDFli\nch Geschlecht und Hautfarbe.\n\nKann nur einmal verwendet werden.",
      fr: "Un miroir myst\xE9rieux.\n\nVous permet de modifier n'importe quel\naspect de votre apparence de base, y\ncompris le sexe et le teint.\n\nNe peut \xEAtre utilis\xE9 qu'une seule\nfois.",
      it: "Uno specchio misterioso.\n\nTi permette di cambiare ogni aspetto\ndel tuo look di base, inclusi genere\ne colore della pelle.\n\nPu\xF2 essere usato una volta sola.",
      es: "Un espejo misterioso.\n\nTe permite cambiar cualquier aspecto\nde la apariencia base, incluyendo\ng\xE9nero y t\xF3no de piel.\n\nPuede ser usado s\xF3lo una vez.",
      ja: "A mysterious mirror.\n\nAllows you to change any aspect of\nyour base appearance, including\ngender and skin tone.\n\nCan only be used once.",
      tw: "\u795E\u7955\u7684\u93E1\u5B50.\n\n\u53EF\u4EE5\u6539\u8B8A\u57FA\u672C\u5916\u8C8C\u7684\u4EFB\u610F\u65B9\u9762, \u5305\u62EC\u6027\u5225\u548C\u819A\u8272.\n\n\u53EA\u80FD\u7528\u4E00\u6B21."
    }
  },
  "1485": {
    name: {
      en: "Mysterious Cherish Ball (2024)",
      cn: "\u795E\u79D8Cherish Ball (2024)",
      de: "Mysteri\xF6ser Jubelball (2024)",
      fr: "Myst\xE9rieuse M\xE9moire Ball (2024)",
      it: "Pregio Ball Misteriosa (2024)",
      es: "Gloria Ball Misteriosa (2024)",
      ja: "Mysterious \u30D7\u30EC\u30B7\u30E3\u30B9\u30DC\u30FC\u30EB (2024)",
      tw: "\u795E\u7955Cherish Ball (2024)"
    },
    description: {
      en: "A mysterious Cherish Ball which\ncontains an unknown reward. It has a\nhigh base chance to contain a Shiny\nPok\xE9mon (1/6,000).\n\nExclusive to Lunar New Year 2024.",
      cn: "\u88C5\u7740\u672A\u77E5\u5956\u52B1\u7684\u795E\u79D8Cherish Ball. \u9AD8\u57FA\u7840\u95EA\u7387(1/6,000)\n\u83B7\u5F97\u95EA\u5149Pok\xE9mon.\n\n2024\u6625\u8282\u7279\u6709.",
      de: "Eine geheimnisvolle Jubelball, die\neine unbekannte Belohnung enth\xE4lt. Es\nhat eine hohe Basischance, ein\ngl\xE4nzendes Pok\xE9mon zu enthalten\n(1/6.500).\n\nExklusiv f\xFCr Lunar New Year 2024.",
      fr: "Une myst\xE9rieuse M\xE9moire Ball qui\ncontient une r\xE9compense inconnue. Il\na de fortes chances de contenir un\nPok\xE9mon shiny (1/6 000).\n\nExclusif au Nouvel An lunaire 2024.",
      it: "Una Pregio Ball misteriosa che\ncontiene una ricompensa sconosciuta.\nHa un'alta probabilit\xE0 di contenere\nun Pok\xE9mon Cromatico (1/6000).\n\nEsclusivo del Nuovo Anno Lunare 2024.",
      es: "Una Gloria Ball misteriosa que\ncontiene una recompensa desconocida.\nTiene una alta probabilidad de\ncontener un Pok\xE9mon Variocolor\n(1/6,000).\n\nExclusivo del A\xF1o Nuevo Lunar 2024.",
      ja: "A mysterious \u30D7\u30EC\u30B7\u30E3\u30B9\u30DC\u30FC\u30EB which contains\nan unknown reward. It has a high base\nchance to contain a Shiny \u30DD\u30B1\u30E2\u30F3\n(1/6,000).\n\nExclusive to Lunar New Year 2024.",
      tw: "\u88DD\u8457\u672A\u77E5\u734E\u52F5\u7684\u795E\u7955Cherish Ball. \u9AD8\u57FA\u790E\u9583\u7387(1/6,000)\n\u7372\u5F97\u9583\u5149Pok\xE9mon.\n\n2024\u6625\u7BC0\u7279\u6709."
    }
  },
