  "1498": {
    name: {
      en: "Mysterious Dusk Ball (2024)",
      cn: "\u795E\u79D8Dusk Ball (2024)",
      de: "Geheimnisvoller Finsterball (2024)",
      fr: "Sombre Ball Myst\xE9rieuse (2024)",
      it: "Scuro Ball Misteriosa (2024)",
      es: "Ocaso Ball Misteriosa (2024)",
      ja: "Mysterious \u30C0\u30FC\u30AF\u30DC\u30FC\u30EB (2024)",
      tw: "\u795E\u7955Dusk Ball (2024)"
    },
    description: {
      en: "A mysterious Dusk Ball which contains\nan unknown reward. It has a high base\nchance to contain a Shiny Pok\xE9mon\n(1/6,000).",
      cn: "\u88C5\u7740\u672A\u77E5\u5956\u52B1\u7684\u795E\u79D8Dusk Ball. \u9AD8\u57FA\u7840\u95EA\u7387(1/6,000)\u83B7\u5F97\u95EA\n\u5149Pok\xE9mon.",
      de: "Eine geheimnisvolle Finsterball, die\neine unbekannte Belohnung enth\xE4lt. Es\nhat eine hohe Basischance, ein\ngl\xE4nzendes Pok\xE9mon zu enthalten\n(1/6.000).",
      fr: "Une myst\xE9rieuse Sombre Ball qui\ncontient une r\xE9compense inconnue.\nElle a une forte chance de contenir\nun Pok\xE9mon shiny (1/6 000).",
      it: "Una Scuro Ball misteriosa che contiene\nuna ricompensa sconosciuta. Ha\nun'alta probabilit\xE0 di contenere un\nPok\xE9mon Cromatico (1/6.000).",
      es: "Una Ocaso Ball misteriosa que contiene\nuna recompensa desconocida. Tiene una\nalta probabilidad de contener un\nPok\xE9mon Variocolor (1/6,000).",
      ja: "A mysterious \u30C0\u30FC\u30AF\u30DC\u30FC\u30EB which contains an\nunknown reward. It has a high base\nchance to contain a Shiny \u30DD\u30B1\u30E2\u30F3\n(1/6,000).",
      tw: "\u88DD\u8457\u672A\u77E5\u734E\u52F5\u7684\u795E\u7955Dusk Ball. \u9AD8\u57FA\u790E\u9583\u7387(1/6,000)\u7372\u5F97\u9583\n\u5149Pok\xE9mon."
    }
  },
  "1499": {
    name: {
      en: "Dream Essence",
      cn: "\u68A6\u4E4B\u9999\u7CBE(Dream Essence)",
      de: "Traum-Essenz",
      fr: "Essence de r\xEAve",
      it: "Essenza di Sogni",
      es: "Esencia de Sue\xF1o",
      ja: "Dream Essence",
      tw: "\u5922\u4E4B\u9999\u7CBE(Dream Essence)"
    },
    description: {
      en: "A distillation of stolen dreams. It\nmay be used to alter the IVs of\ncertain Pok\xE9mon by 1.\n\nConsumed upon use.",
      cn: "\u53EF\u4EE5\u4FEE\u6B63\u67D0\u4E9BPok\xE9mon1\u70B9\u4E2A\u4F53\u503C\u7684\u88AB\u76D7\u4E4B\u68A6\u7684\u7CBE\u534E.\n\n\u4E00\u6B21\u6027\u6D88\u8017\u54C1.",
      de: "Ein Destillat aus gestohlenen Tr\xE4umen.\nKann dazu dienen, die DVs bestimmter\nPok\xE9mon um 1 anzupassen.\n\nWird bei Verwendung aufgebraucht.",
      fr: "Une distillation de r\xEAves vol\xE9s. Elle\npeut \xEAtre utilis\xE9e pour modifier les\nIVs de certains Pok\xE9mon de 1.\n\nConsomm\xE9 \xE0 l'utilisation.",
      it: "Un distillato di sogni rubati. Pu\xF2\nessere utilizzato per alterare gli IV\ndi certi Pok\xE9mon di 1.\n\nConsumato all'uso.",
      es: "Una distilaci\xF3n de sue\xF1os robados.\nPuede ser usada para alterar los IVs\nde ciertos Pok\xE9mon en 1.\n\nSe consume al usarla.",
      ja: "A distillation of stolen dreams. It\nmay be used to alter the IVs of\ncertain \u30DD\u30B1\u30E2\u30F3 by 1.\n\nConsumed upon use.",
      tw: "\u53EF\u4EE5\u4FEE\u6B63\u67D0\u4E9BPok\xE9mon1\u9EDE\u500B\u9AD4\u503C\u7684\u88AB\u76DC\u4E4B\u5922\u7684\u7CBE\u83EF.\n\n\u4E00\u6B21\u6027\u6D88\u8017\u54C1."
    }
  },
