  "1510": {
    name: {
      en: "Safety Goggles",
      cn: "\u9632\u5C18\u62A4\u76EE\u955C",
      de: "Sicherheitsbrille",
      fr: "Lunettes Filtres",
      it: "Visierantisabbia",
      es: "Gafas Protectoras",
      ja: "Safety Goggles",
      tw: "\u9632\u5875\u8B77\u76EE\u93E1"
    },
    description: {
      en: "An item to be held by a Pok\xE9mon. These\nprotective goggles guard against\npowder moves, spore moves, and\nSandstorm damage.",
      cn: "\u643A\u5E26\u540E, \u53EF\u514D\u75AB\u7C89\u672B\u7C7B\u6280\u80FD, \u5B62\u5B50\u7279\u6027\u4EE5\u53CA\u6C99\u66B4\u5929\u6C14.",
      de: "Ein Item, das von einem Pok\xE9mon\ngetragen werden kann. Diese Brille\nbewahrt den Tr\xE4ger vor Puder-Attacke\nn, Sporen-Attacken und Schaden durch\nSandsturm.",
      fr: "Un objet \xE0 faire tenir \xE0 un Pok\xE9mon.\nCes lunettes de protection prot\xE8gent\ncontre les attaques de poudre, les\nattaques de spore et les d\xE9g\xE2ts de\nTemp\xEAte de sable.",
      it: "Strumento da far tenere a un Pok\xE9mon.\nQuesti occhiali proteggono dalle mosse\nche rilasciano polvere, mosse spora e\ndal danno delle Tempeste di Sabbia.",
      es: "Un objeto equipable de Pok\xE9mon. Estas\ngafas protectoras resguardan contra\nmovimientos polvo, movimientos\nespora, y da\xF1o de Tormenta de Arena.",
      ja: "An item to be held by a \u30DD\u30B1\u30E2\u30F3. These\nprotective goggles guard against\npowder moves, spore moves, and\nSandstorm damage.",
      tw: "\u651C\u5E36\u5F8C, \u53EF\u514D\u75AB\u7C89\u672B\u985E\u6280\u80FD, \u5B62\u5B50\u7279\u6027\u4EE5\u53CA\u6C99\u66B4\u5929\u6C23."
    }
  },
  "1511": {
    name: {
      en: "Type Policy",
      cn: "\u5F31\u70B9\u4FDD\u9669",
      de: "Typenschutz",
      fr: "Type-Assurance",
      it: "Vulneropolizza",
      es: "Poliza de Tipo",
      ja: "Type Policy",
      tw: "\u5F31\u9EDE\u4FDD\u96AA"
    },
    description: {
      en: "An item to be held by a Pok\xE9mon. If\nthe holder is hit by a super-effecti\nve move, Attack and Sp. Attack will\nsharply increase.\n\nConsumed upon use.",
      cn: "\u643A\u5E26\u540E, \u906D\u5230\u6548\u679C\u7EDD\u4F73\u653B\u51FB\u65F6\u653B\u51FB\u548C\u7279\u653B\u4F1A\u5927\u5E45\u63D0\u5347.\n\n\u4E00\u6B21\u6027\u6D88\u8017\u54C1.",
      de: "Ein Item, das von einem Pok\xE9mon\ngetragen werden kann. Wird der Tr\xE4ger\nvon einer sehr effektiven Attacke\ngetroffen, steigen Angriff und\nSpezial-Angriff stark an.\n\nDieser Gegenstand wird bei Verwendung\nverbraucht.",
      fr: "Un objet \xE0 faire tenir \xE0 un Pok\xE9mon.\nSi le porteur est touch\xE9 par une\nattaque super efficace, son Attaque\net Attaque Sp. augmenteront\nbeaucoup.\nConsomm\xE9 lors de l'utilisation.",
      it: "Strumento da far tenere a un Pok\xE9mon.\nSe chi lo tiene viene colpito da una\nmossa superefficace, l'Attacco e\nl'Attacco Sp. aumenteranno di molto.\n\nCunsumato all'uso.",
      es: "Un objeto equipable de Pok\xE9mon. Si el\nportador es golpeado por ataques\nsuper efectivos, el Atk. y Sp. Atk\nincrementar\xE1n mucho.\n\nSe consume al usarlo.",
      ja: "An item to be held by a \u30DD\u30B1\u30E2\u30F3. If the\nholder is hit by a super-effective\nmove, Attack and Sp. Attack will\nsharply increase.\n\nConsumed upon use.",
      tw: "\u651C\u5E36\u5F8C, \u906D\u5230\u6548\u679C\u7D55\u4F73\u653B\u64CA\u6642\u653B\u64CA\u548C\u7279\u653B\u6703\u5927\u5E45\u63D0\u5347.\n\n\u4E00\u6B21\u6027\u6D88\u8017\u54C1."
    }
  },
