  "5011": {
    name: {
      en: "Luxury Ball",
      cn: "Luxury Ball",
      de: "Luxusball",
      fr: "Luxe Ball",
      it: "Chic Ball",
      es: "Lujo Ball",
      ja: "\u30B4\u30FC\u30B8\u30E3\u30B9\u30DC\u30FC\u30EB",
      tw: "Luxury Ball"
    },
    description: {
      en: "A luxurious Pok\xE9 Ball which helps grow\nyour friendship with a Pok\xE9mon\nquickly. It works well on Pok\xE9mon\nwhich evolve due to happiness.",
      cn: "\u80FD\u5FEB\u901F\u63D0\u5347\u4E0EPok\xE9mon\u4EB2\u5BC6\u5EA6\u7684\u8212\u9002\u5B9C\u5C45\u7684Pok\xE9 Ball.\n\u5BF9\u4F9D\u9760\u4EB2\u5BC6\u5EA6\u8FDB\u5316\u7684Pok\xE9mon\u4F5C\u7528\u663E\u8457.",
      de: "Ein luxuri\xF6ser Pok\xE9ball, das dazu\nbeitr\xE4gt, dass deine Freundschaft mit\neinem Pok\xE9mon schnell w\xE4chst. Es\nfunktioniert gut bei Pok\xE9mon, die\nsich aufgrund von Gl\xFCck entwickeln.",
      fr: "Une Pok\xE9 Ball de luxe qui permet de\nd\xE9velopper rapidement votre amiti\xE9\navec un Pok\xE9mon. Elle fonctionne bien\nsur les Pok\xE9mon qui \xE9voluent gr\xE2ce au\nbonheur.",
      it: "Una Pok\xE9 Ball lussuosa che aiuta a\naumentare la tua amicizia con un\nPok\xE9mon velocemente. Funziona bene\ncon Pok\xE9mon che evolvono tramite\nfelicit\xE0.",
      es: "Una Pok\xE9 Ball lujosa que ayuda a\ncrecer la amistad con un Pok\xE9mon\nr\xE1pidamente. Funciona bien con\nPok\xE9mon que evolucionan por\nfelicidad.",
      ja: "A luxurious \u30E2\u30F3\u30B9\u30BF\u30FC\u30DC\u30FC\u30EB which helps grow\nyour friendship with a \u30DD\u30B1\u30E2\u30F3 quickly.\nIt works well on \u30DD\u30B1\u30E2\u30F3 which evolve\ndue to happiness.",
      tw: "\u80FD\u5FEB\u901F\u63D0\u5347\u8207Pok\xE9mon\u89AA\u5BC6\u5EA6\u7684\u8212\u9069\u5B9C\u5C45\u7684Pok\xE9 Ball.\n\u5C0D\u4F9D\u9760\u89AA\u5BC6\u5EA6\u9032\u5316\u7684Pok\xE9mon\u4F5C\u7528\u986F\u8457."
    }
  },
