  "5222": {
    name: {
      en: "SilverPowder",
      cn: "SilverPowder",
      de: "Silberstaub",
      fr: "Poudre Arg.",
      it: "Argenpolvere",
      es: "Polvo Plata",
      ja: "\u304E\u3093\u306E\u3053\u306A",
      tw: "SilverPowder"
    },
    description: {
      en: "An item to be held by a Pok\xE9mon.\nIt increases the power of Bug-type\nmoves by 20%.\n\nIt is popular among certain Move\nTutors.",
      cn: "\u7ED9Pok\xE9mon\u643A\u5E26\u7684\u9053\u5177.\n\u866B\u7CFB\u6280\u80FD\u5A01\u529B\u63D0\u534720%.\n\n\u5728\u4E00\u4E9B\u62DB\u5F0F\u6559\u5B66\u8005\u4E2D\u5F88\u53D7\u6B22\u8FCE.",
      de: "Ein Gegenstand der von Pok\xE9mon\ngehalten werden kann.\nEs erh\xF6ht die Power von K\xE4ferattacken\num 20%.\n\nBeliebt bei bestimmten Lehrmeistern\nvon Attacken.",
      fr: "Un objet \xE0 faire tenir \xE0 un Pok\xE9mon.\nAugmente de 20% la puissance des\ncapacit\xE9s de type Insecte.\n\nIl est populaire parmi certains\nTuteurs de Capacit\xE9s.",
      it: "Strumento da far tenere a un Pok\xE9mon.\nPolvere argentea e brillante che\npotenzia le mosse di tipo Coleottero\ndel 20%.\n\nMolto popolare tra alcuni Insegnamoss\ne.",
      es: "Objeto que debe llevar un Pok\xE9mon.\nAumenta la potencia de los movimientos\nde tipo Bicho un 20%.\n\nEs popular entre algunos Tutores de\nMovimientos.",
      ja: "An item to be held by a \u30DD\u30B1\u30E2\u30F3.\n\nIt increases the power of\nBug-type moves by 20%.\n\nIt is popular among certain Move\nTutors.",
      tw: "\u7D66Pok\xE9mon\u651C\u5E36\u7684\u9053\u5177.\n\u87F2\u7CFB\u6280\u80FD\u5A01\u529B\u63D0\u534720%.\n\n\u5728\u4E00\u4E9B\u62DB\u5F0F\u6559\u5B78\u8005\u4E2D\u5F88\u53D7\u6B61\u8FCE."
    }
  },
  "5223": {
    name: {
      en: "Amulet Coin",
      cn: "Amulet Coin",
      de: "M\xFCnzamulett",
      fr: "Pi\xE8ce Rune",
      it: "Monetamuleto",
      es: "Mon. Amuleto",
      ja: "\u304A\u307E\u3082\u308A\u3053\u3070\u3093",
      tw: "Amulet Coin"
    },
    description: {
      en: "An item which increases the amount of\nMoney gained from trainer battles for\na short period of time.\n\n1.50x Money gain.\nStacks with other bonuses.\nConsumed upon use.\nEffects last 1 hour.",
      cn: "\u77ED\u65F6\u95F4\u5185\u589E\u52A0\u8BAD\u7EC3\u5BB6\u5BF9\u6218\u4E2D\u6240\u83B7\u91D1\u94B1.\n\n\u83B7\u5F971.5\u500D.\n\u4E0E\u5176\u4ED6\u52A0\u6210\u76F8\u53E0\u52A0.\n\u4E00\u6B21\u6027\u6D88\u8017\u54C1.\n\u6709\u6548\u671F1\u5C0F\u65F6.",
      de: "Ein Gegenstand, der die Geldmenge, die\ndurch Trainerk\xE4mpfe gewonnen wird,\nf\xFCr eine kurze Zeit erh\xF6ht.\n\n1,50x Geldgewinn.\nStapelt sich mit anderen Boni.\nBei Verwendung verbraucht.\nDie Wirkung h\xE4lt 1 Stunde an.",
      fr: "Un objet qui augmente la quantit\xE9\nd'argent gagn\xE9e lors des combats de\ndresseurs pendant une courte p\xE9riode\nde temps.\n\n1.50x d'argent gagn\xE9 en plus.\nSe cumule avec les autres bonus.\nConsomm\xE9 \xE0 l'utilisation.\nL'effet dure une heure.",
      it: "Strumento che aumenta il denaro\nguadagnato dalle lotte con altri\nallenatori per un breve periodo di\ntempo.\n\n1.5x Denaro guadagnato.\nCumulativo con altri bonus.\nSi consuma dopo l'utilizzo.\nL'effetto dura 1 ora.",
      es: "Amuleto que aumenta el dinero recibido\nen combates de entrenador durante\npoco tiempo.\n\n50% m\xE1s de del dinero base.\nSe acumula con otros bonus.\nSe consume al usarlo.\nSu efecto dura 1 hora.",
      ja: "An item which increases the amount of\nMoney gained from trainer battles for\na short period of time.\n\n1.50x Money gain.\nStacks with other bonuses.\nConsumed upon use.\nEffects last 1 hour.",
      tw: "\u77ED\u6642\u9593\u5167\u589E\u52A0\u8A13\u7DF4\u5BB6\u5C0D\u6230\u4E2D\u6240\u7372\u91D1\u9322.\n\n\u7372\u5F971.5\u500D.\n\u8207\u5176\u4ED6\u52A0\u6210\u76F8\u758A\u52A0.\n\u4E00\u6B21\u6027\u6D88\u8017\u54C1.\n\u6709\u6548\u671F1\u5C0F\u6642."
    }
  },
