  "5253": {
    name: {
      en: "Shell Bell",
      cn: "Shell Bell",
      de: "Seegesang",
      fr: "Grelot Coque",
      it: "Conchinella",
      es: "Camp. Concha",
      ja: "\u304B\u3044\u304C\u3089\u306E\u3059\u305A",
      tw: "Shell Bell"
    },
    description: {
      en: "An item to be held by a Pok\xE9mon.\nIt restores HP to the holder equal to\n12.5% of damage inflicted by a move.\n\nThe effects of this item can be\nnullified by the Heal Block ability.",
      cn: "\u7ED9Pok\xE9mon\u643A\u5E26\u7684\u9053\u5177.\n\u4F7F\u7528\u6280\u80FD\u653B\u51FB\u65F6, \u6240\u9020\u6210\u5168\u90E8\u4F24\u5BB3\u7684\u603B\u548C\u768412.5%\u56DE\u590D\u643A\u5E26\u8005\u7684HP.\n\nHeal Block\u7279\u6027\u80FD\u4F7F\u4E4B\u65E0\u6548.",
      de: "Ein Gegenstand, der von einem Pok\xE9mon\ngehalten werden kann.\nEr gibt dem Besitzer 12,5% des\nSchadens, der durch eine Bewegung\nverursacht wird, zur\xFCck.\n\nDie Effekte dieses Gegenstands k\xF6nnen\ndurch die Heilblockade F\xE4higkeit\naufgehoben werden.",
      fr: "Un objet \xE0 faire tenir \xE0 un Pok\xE9mon.\nIl restaure les PV du teneur d'un\nmontant \xE9gal \xE0 12.5% des d\xE9g\xE2ts\ninflig\xE9s par une capacit\xE9.\n\nLes effets de cet objet peuvent \xEAtre\nannul\xE9s par le talent Anti-Soin.",
      it: "Strumento da far tenere a un Pok\xE9mon.\nChi lo tiene recupera il 12.5% del\ndanno inflitto.\n\nIl suo effetto pu\xF2 essere annullato\ncon l'abilit\xE0 Anticura.",
      es: "Objeto que debe llevar un Pok\xE9mon.\nRestaura los PS del Pok\xE9mon que lo\nlleva iguales al 12,5% del da\xF1o\ninfligido por un movimiento.\n\nEl efecto de este objeto puede ser\nanulado por la habilidad Anticura.",
      ja: "An item to be held by a \u30DD\u30B1\u30E2\u30F3.\nIt restores HP to the holder equal to\n12.5% of damage inflicted by a move.\nThe effects of this item can be\nnullified by the ability \u304B\u3044\u3075\u304F\u3075\u3046\u3058.",
      tw: "\u7D66Pok\xE9mon\u651C\u5E36\u7684\u9053\u5177.\n\u4F7F\u7528\u6280\u80FD\u653B\u64CA\u6642, \u6240\u9020\u6210\u5168\u90E8\u50B7\u5BB3\u7684\u7E3D\u548C\u768412.5%\u56DE\u8986\u651C\u5E36\u8005\u7684HP.\n\nHeal Block\u7279\u6548\u80FD\u4F7F\u4E4B\u7121\u6548."
    }
  },
  "5254": {
    name: {
      en: "Sea Incense",
      cn: "Sea Incense",
      de: "Seerauch",
      fr: "Encens Mer",
      it: "Marearoma",
      es: "Incie. Mar.",
      ja: "\u3046\u3057\u304A\u306E\u304A\u3053\u3046",
      tw: "Sea Incense"
    },
    description: {
      en: "An item to be held by a Pok\xE9mon.\nIt increases the power of Water-type\nmoves by 20%.\n\nIf held by a Marill or Azumarill while\nbreeding, it may help them produce a\nAzurill egg.",
      cn: "\u7ED9Pok\xE9mon\u643A\u5E26\u7684\u9053\u5177.\n\u6C34\u7CFB\u6280\u80FD\u5A01\u529B\u63D0\u534720%.\n\nMarill\u6216\u8005Azumarill\u751F\u86CB\u65F6\u643A\u5E26\u5C06\u5F97\u5230Azurill\u7684\u86CB.",
      de: "Ein Gegenstand, der von einem Pok\xE9mon\ngehalten werden muss.\nEr erh\xF6ht die Kraft von Bewegungen des\nTyps Wasser um 20 %.\n\nWenn er von einem Marill oder\nAzumarill w\xE4hrend der Zucht gehalten\nwird, kann er ihnen helfen, ein\nAzurill Ei zu produzieren.",
      fr: "Un objet \xE0 faire tenir \xE0 un Pok\xE9mon.\nAugmente de 20% la puissance des\nattaques de type Eau.\n\nSi tenu par un Marill ou un Azumarill\nlors de la reproduction, il peut les\naider \xE0 produire un oeuf de Azurill.",
      it: "Strumento da far tenere a un Pok\xE9mon.\nPotenzia le mosse di tipo Acqua del\n20%.\n\nSe tenuto da Marill o Azumarill\ndurante l'allevamento, permetter\xE0\nloro di generare un uovo di Azurill.",
      es: "Objeto que puede llevar un Pok\xE9mon.\nAumenta la potencia de los movimientos\nde tipo Agua un 20%.\n\nSi la lleva un Marill o un Azumarill\nal criar, puede ayudar a crear un\nhuevo de Azurill.",
      ja: "An item to be held by a \u30DD\u30B1\u30E2\u30F3.\nIt increases the power of\nWater-type moves by 20%.\n\nIf held by a \u30DE\u30EA\u30EB or\n\u30DE\u30EA\u30EB\u30EA while breeding,\nit may help them produce a \u30EB\u30EA\u30EA egg.",
      tw: "\u7D66Pok\xE9mon\u651C\u5E36\u7684\u9053\u5177.\n\u6C34\u7CFB\u6280\u80FD\u5A01\u529B\u63D0\u534720%.\n\nMarill\u6216\u8005Azumarill\u751F\u86CB\u6642\u651C\u5E36\u5C07\u5F97\u5230Azurill\u7684\u86CB."
    }
  },
