      cn: "\u7ED9Pok\xE9mon\u643A\u5E26\u7684\u9053\u5177.\n\u8FDE\u7EED\u4F7F\u51FA\u76F8\u540C\u62DB\u5F0F\u65F6, \u5A01\u529B\u5C31\u4F1A\u63D0\u534720%, \u6700\u9AD8100%.",
