  "5320": {
    name: {
      en: "Pure Incense",
      cn: "Pure Incense",
      de: "Scheuchrauch",
      fr: "Encens Pur",
      it: "Puroaroma",
      es: "Incie. Puro",
      ja: "\u304D\u3088\u3081\u306E\u304A\u3053\u3046",
      tw: "Pure Incense"
    },
    description: {
      en: "An item to be held by a Pok\xE9mon.\nIt slightly reduces the chance of\nencountering wild Pok\xE9mon.\n\nIf held by a Chimecho while breeding,\nit may help them produce a Chingling\negg.",
      cn: "\u7ED9Pok\xE9mon\u643A\u5E26\u7684\u9053\u5177.\n\u643A\u5E26\u8005\u6392\u914D\u7F6E\u5728\u961F\u4F0D\u9996\u4F4D\u65F6, \u964D\u4F4E\u9047\u89C1\u91CE\u751F\u5B9D\u53EF\u68A6\u7684\u51E0\u7387.\n\n\u751F\u86CB\u65F6\u7531Chimecho\u643A\u5E26\u5C06\u5F97\u5230Chingling\u7684\u86CB.",
      de: "Ein Gegenstand, der von einem Pok\xE9mon\ngehalten werden sollte.\nEr verringert leicht die Wahrscheinli\nchkeit, auf wilde Pok\xE9mon zu treffen.\n\nWenn er von einem Palimpalim bei der\nZucht gehalten wird, kann es ihm\nhelfen, ein Klingplim Ei zu\nproduzieren.",
      fr: "Un objet \xE0 faire tenir \xE0 un Pok\xE9mon.\nR\xE9duit l\xE9g\xE8rement les chances de\nrencontrer des Pok\xE9mon sauvages.\n\nSi tenu par un \xC9oko lors de la\nreproduction, il peut l'aider \xE0\nproduire un \u0153uf de Korillon.",
      it: "Strumento da far tenere a un Pok\xE9mon.\nAiuta ad allontanare i Pok\xE9mon\nselvatici se chi lo tiene \xE8 il primo\ndella squadra.\n\nSe tenuto da Chimecho durante\nl'allevamento, permetter\xE0 loro di\ngenerare un uovo di Chingling.",
      es: "Objeto que debe llevar un Pok\xE9mon.\nReduce un poco la probabilidad de\nencontrar Pok\xE9mon salvajes.\n\nSi lo lleva un Chimecho al criar,\npuede ayudar a crear un huevo de\nChingling.",
      ja: "An item to be held by a \u30DD\u30B1\u30E2\u30F3.\n\nIt slightly reduces\nthe chance of encountering wild \u30DD\u30B1\u30E2\u30F3.\n\nIf held by a \u30C1\u30EA\u30FC\u30F3 while breeding,\nit may help them produce a \u30EA\u30FC\u30B7\u30E3\u30F3 egg.",
      tw: "\u7D66Pok\xE9mon\u651C\u5E36\u7684\u9053\u5177.\n\u651C\u5E36\u8005\u6392\u914D\u7F6E\u5728\u968A\u4F0D\u9996\u4F4D\u6642, \u964D\u4F4E\u9047\u898B\u91CE\u751F\u5BF6\u53EF\u5922\u7684\u6A5F\u7387.\n\n\u751F\u86CB\u6642\u7531Chimecho\u651C\u5E36\u5C07\u5F97\u5230Chingling\u7684\u86CB."
    }
  },
