      ja: "\u306D\u3066\u3044\u308B\u3000\u3042\u3044\u3066\u306E\u3000\u3086\u3081\u3092\u3000\u305F\u3079\u3066 \u3053\u3046\u3052\u304D\u3059\u308B\u3002\u3000\u30C0\u30E1\u30FC\u30B8\u306E\u3000\u306F\u3093\u3076\n\u3093\u306E \uFF28\uFF30\u3092\u3000\u304B\u3044\u3075\u304F\u3000\u3059\u308B\u3002",
